const checkpoints = [];

const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const currentCartId = localStorage.getItem('current_cart_id');

// Determine which cart to inspect
let cartId = null;
if (currentCartId) {
  const cur = carts.find(c => c.id === currentCartId);
  if (cur) cartId = cur.id;
}
if (!cartId && carts.length > 0) {
  // Fallback: most recently created cart
  const sorted = carts.slice().sort((a, b) => {
    const da = new Date(a.createdAt || 0).getTime();
    const db = new Date(b.createdAt || 0).getTime();
    return db - da;
  });
  cartId = sorted[0].id;
}

const itemsForCart = cartItems.filter(ci => ci.cartId === cartId);

// All products that qualify per task criteria
const qualifyingProducts = products.filter(p => {
  if (!p) return false;
  if (p.categorySlug !== 'laptops') return false;
  if (p.usageType !== 'business') return false;
  if (typeof p.price !== 'number' || p.price > 1200) return false;
  if (typeof p.ramGB !== 'number' || p.ramGB < 16) return false;
  if (typeof p.storageCapacityGB !== 'number' || p.storageCapacityGB < 512) return false;
  if (p.storageType !== 'ssd') return false;
  if (typeof p.screenSizeInches !== 'number' || p.screenSizeInches < 14 || p.screenSizeInches > 15.6) return false;
  if (typeof p.rating !== 'number' || p.rating < 4.0) return false;
  return true;
});

let cheapestPrice = null;
if (qualifyingProducts.length > 0) {
  cheapestPrice = qualifyingProducts.reduce((min, p) => (min === null || p.price < min ? p.price : min), null);
}

const qualifyingProductIds = new Set(qualifyingProducts.map(p => p.id));

// Helper: items in cart for qualifying products
const qualifyingItemsAnyQty = itemsForCart.filter(ci => {
  const p = products.find(pr => pr.id === ci.productId);
  return p && qualifyingProductIds.has(p.id) && (ci.quantity || 0) >= 1;
});

const qualifyingItemsQty2 = itemsForCart.filter(ci => {
  const p = products.find(pr => pr.id === ci.productId);
  return p && qualifyingProductIds.has(p.id) && (ci.quantity || 0) >= 2;
});

// Items that are for the cheapest qualifying product and have quantity >= 2
const cheapestQualifyingItemsQty2 = qualifyingItemsQty2.filter(ci => {
  const p = products.find(pr => pr.id === ci.productId);
  return p && cheapestPrice !== null && p.price === cheapestPrice;
});

// CP1 (0.30): Cart contains at least one qualifying business laptop (specs match) with quantity >=1
checkpoints.push({
  passed: qualifyingItemsAnyQty.length > 0,
  weight: 0.30
});

// CP2 (0.30): Cart contains at least one qualifying business laptop with quantity >=2
checkpoints.push({
  passed: qualifyingItemsQty2.length > 0,
  weight: 0.30
});

// CP3 (0.40): The laptop with quantity >=2 is the cheapest qualifying option
checkpoints.push({
  passed: cheapestQualifyingItemsQty2.length > 0,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('software_quote_requests') || '[]');

// Target window: next month (April 5–20, 2026) given baseline March 2026
const windowStart = new Date('2026-04-05T00:00:00Z');
const windowEnd = new Date('2026-04-20T23:59:59Z');

// Stepwise filters
const svcAndType = requests.filter(r => r && r.serviceCategory === 'crm_integration' && r.projectType === 'custom_crm_integration');

const budgetFiltered = svcAndType.filter(r => {
  const min = typeof r.estimatedBudgetMin === 'number' ? r.estimatedBudgetMin : 0;
  const max = typeof r.estimatedBudgetMax === 'number' ? r.estimatedBudgetMax : 0;
  return min >= 15000 && max <= 25000 && min <= max;
});

const dateAndContactFiltered = budgetFiltered.filter(r => {
  const d = new Date(r.desiredStartDate || '');
  if (isNaN(d.getTime())) return false;
  if (!(d >= windowStart && d <= windowEnd)) return false;
  if (r.preferredContactMethod !== 'phone') return false;
  if (!r.phone || String(r.phone).trim().length === 0) return false;
  return true;
});

const fullMatch = dateAndContactFiltered.filter(r => {
  const desc = (r.projectDescription || '').toLowerCase();
  const hasCRM = desc.includes('crm');
  const hasBilling = desc.includes('billing');
  return hasCRM && hasBilling;
});

// CP1 (0.25): A request exists for the CRM integration category and custom CRM integration project type
checkpoints.push({
  passed: svcAndType.length > 0,
  weight: 0.25
});

// CP2 (0.25): Such a request uses a budget range fully between $15k and $25k
checkpoints.push({
  passed: budgetFiltered.length > 0,
  weight: 0.25
});

// CP3 (0.25): Such a request has a desired start date between April 5–20, 2026 and prefers phone contact with a phone number
checkpoints.push({
  passed: dateAndContactFiltered.length > 0,
  weight: 0.25
});

// CP4 (0.25): Such a request describes integrating CRM with billing (project description mentions CRM and billing)
checkpoints.push({
  passed: fullMatch.length > 0,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('onsite_maintenance_bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');

// Date window: April 10–20, 2026 (next month from March 2026)
const windowStart = new Date('2026-04-10T00:00:00Z');
const windowEnd = new Date('2026-04-20T23:59:59Z');

const svcAndDevices = bookings.filter(b => {
  if (!b) return false;
  if (b.serviceType !== 'workstation_maintenance') return false;
  const n = typeof b.numDevices === 'number' ? b.numDevices : 0;
  return n >= 10 && n <= 20;
});

const withDate = svcAndDevices.filter(b => {
  const d = new Date(b.preferredDate || '');
  if (isNaN(d.getTime())) return false;
  return d >= windowStart && d <= windowEnd;
});

const withMorningSlot = withDate.filter(b => {
  const slot = timeSlots.find(ts => ts.id === b.timeSlotId);
  return slot && slot.timeOfDay === 'morning';
});

const withLocation = withMorningSlot.filter(b => {
  const addr1 = (b.officeAddressLine1 || '').trim();
  const city = (b.city || '').trim();
  const postal = (b.postalCode || '').trim();
  const contactName = (b.contactName || '').trim();
  const contactEmail = (b.contactEmail || '').trim();
  return addr1.length > 0 && city.length > 0 && postal.length > 0 && contactName.length > 0 && contactEmail.length > 0;
});

// CP1 (0.25): Booking for workstation_maintenance with 10–20 devices
checkpoints.push({
  passed: svcAndDevices.length > 0,
  weight: 0.25
});

// CP2 (0.25): Such a booking scheduled between April 10–20, 2026
checkpoints.push({
  passed: withDate.length > 0,
  weight: 0.25
});

// CP3 (0.25): Such a booking uses a morning time slot
checkpoints.push({
  passed: withMorningSlot.length > 0,
  weight: 0.25
});

// CP4 (0.25): Such a booking includes non-empty office address, city, postal code, and contact details
checkpoints.push({
  passed: withLocation.length > 0,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('it_support_plans') || '[]');
const signups = JSON.parse(localStorage.getItem('it_support_signups') || '[]');

// Active plans that meet feature requirements
const qualifyingPlans = plans.filter(p => p && p.status === 'active' && p.has24x7Support && p.includesOnSiteVisits);

let cheapestPrice = null;
if (qualifyingPlans.length > 0) {
  cheapestPrice = qualifyingPlans.reduce((min, p) => (min === null || p.monthlyPrice < min ? p.monthlyPrice : min), null);
}

const qualifyingPlanIds = new Set(qualifyingPlans.map(p => p.id));

const signupsForQualifyingPlans = signups.filter(s => {
  const plan = plans.find(p => p.id === s.planId);
  return plan && qualifyingPlanIds.has(plan.id);
});

const signupsForCheapestPlan = signupsForQualifyingPlans.filter(s => {
  const plan = plans.find(p => p.id === s.planId);
  return plan && cheapestPrice !== null && plan.monthlyPrice === cheapestPrice;
});

const detailedSignup = signupsForCheapestPlan.find(s => {
  const nameOk = (s.companyName || '').trim().length > 0;
  const phoneOk = (s.businessPhone || '').trim().length > 0;
  const email = (s.businessEmail || '').trim();
  const emailOk = email.includes('@');
  return nameOk && phoneOk && emailOk && s.status === 'started';
});

// CP1 (0.40): There is a signup whose plan includes 24/7 support and on-site visits
checkpoints.push({
  passed: signupsForQualifyingPlans.length > 0,
  weight: 0.40
});

// CP2 (0.40): That signup is for the cheapest such qualifying plan
checkpoints.push({
  passed: signupsForCheapestPlan.length > 0,
  weight: 0.40
});

// CP3 (0.20): The signup for the cheapest qualifying plan has basic company/contact info filled and status 'started'
checkpoints.push({
  passed: !!detailedSignup,
  weight: 0.20
});

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('knowledge_base_articles') || '[]');
const models = JSON.parse(localStorage.getItem('hardware_models') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles') || '[]');
const folders = JSON.parse(localStorage.getItem('knowledge_base_folders') || '[]');

// Saved articles that are about server overheating and tied to a server hardware model
const qualifyingSaved = saved.filter(sa => {
  const art = articles.find(a => a.id === sa.articleId);
  if (!art || !art.isPublished) return false;
  const model = models.find(m => m.id === art.modelId);
  if (!model || model.type !== 'server') return false;
  const text = ((art.title || '') + ' ' + (art.content || '') + ' ' + (art.excerpt || '') + ' ' + ((art.keywords || []).join(' '))).toLowerCase();
  return text.includes('server overheating');
});

const serverIssuesFolder = folders.find(f => (f.name || '').toLowerCase() === 'server issues');
let qualifyingInServerIssuesFolder = [];
if (serverIssuesFolder) {
  qualifyingInServerIssuesFolder = qualifyingSaved.filter(sa => sa.folderId === serverIssuesFolder.id);
}

// CP1 (0.70): User has saved at least one KB article about server overheating for a server model
checkpoints.push({
  passed: qualifyingSaved.length > 0,
  weight: 0.70
});

// CP2 (0.30): Such an article is saved inside a folder named 'Server Issues'
checkpoints.push({
  passed: serverIssuesFolder != null && qualifyingInServerIssuesFolder.length > 0,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');
const currentCartId = localStorage.getItem('current_cart_id');

// Determine cart to inspect
let cartId = null;
if (currentCartId) {
  const cur = carts.find(c => c.id === currentCartId);
  if (cur) cartId = cur.id;
}
if (!cartId && carts.length > 0) {
  const sorted = carts.slice().sort((a, b) => {
    const da = new Date(a.createdAt || 0).getTime();
    const db = new Date(b.createdAt || 0).getTime();
    return db - da;
  });
  cartId = sorted[0].id;
}

const itemsForCart = cartItems.filter(ci => ci.cartId === cartId);

function lowerTags(p) {
  return Array.isArray(p.tags) ? p.tags.map(t => String(t).toLowerCase()) : [];
}

function qualifyingItemsForRole(roleFn) {
  return itemsForCart.filter(ci => {
    const p = products.find(pr => pr.id === ci.productId);
    if (!p) return false;
    if (p.categorySlug !== 'accessories') return false;
    if (typeof p.price !== 'number' || p.price >= 50) return false;
    if (typeof p.rating !== 'number' || p.rating < 4.0) return false;
    if (!p.freeShipping) return false;
    const tags = lowerTags(p);
    if (!roleFn(tags)) return false;
    return (ci.quantity || 0) >= 1;
  });
}

const keyboardItems = qualifyingItemsForRole(tags => tags.includes('keyboard') || tags.includes('keyboards'));
const mouseItems = qualifyingItemsForRole(tags => tags.includes('mouse') || tags.includes('mice'));
const cableItems = qualifyingItemsForRole(tags => tags.includes('cable') || tags.includes('cables'));

const cart = carts.find(c => c.id === cartId) || null;
const save10 = promoCodes.find(p => (p.code || '').toUpperCase() === 'SAVE10');
const promoApplied = !!(cart && save10 && cart.promoCodeId === save10.id);

// CP1 (0.30): Cart includes at least one qualifying keyboard accessory line (under $50, >=4 stars, free shipping)
checkpoints.push({
  passed: keyboardItems.length > 0,
  weight: 0.30
});

// CP2 (0.30): Cart includes at least one qualifying mouse accessory line with same constraints
checkpoints.push({
  passed: mouseItems.length > 0,
  weight: 0.30
});

// CP3 (0.30): Cart includes at least one qualifying cable accessory line with same constraints
checkpoints.push({
  passed: cableItems.length > 0,
  weight: 0.30
});

// CP4 (0.10): SAVE10 promo code is applied to the cart
checkpoints.push({
  passed: promoApplied,
  weight: 0.10
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('training_events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const now = new Date();

const matchingEventRegs = regs.filter(r => {
  const ev = events.find(e => e.id === r.eventId);
  if (!ev) return false;
  const topic = (ev.topic || '').toLowerCase();
  if (!topic.includes('cloud migration')) return false;
  if (ev.status !== 'scheduled') return false;
  const start = new Date(ev.startDateTime || '');
  if (isNaN(start.getTime()) || start <= now) return false;
  if (r.numSeats !== 1) return false;
  // training or webinar session (webinar, training_session, or workshop)
  const et = ev.eventType;
  if (et !== 'webinar' && et !== 'training_session' && et !== 'workshop') return false;
  return true;
});

const matchingWithPrefs = matchingEventRegs.filter(r => {
  return r.attendeeTimeZone === 'utc_minus_05_00' && r.experienceLevel === 'intermediate';
});

// CP1 (0.50): Registration for exactly one seat on a future scheduled cloud migration training/webinar/workshop event
checkpoints.push({
  passed: matchingEventRegs.length > 0,
  weight: 0.50
});

// CP2 (0.50): That registration uses Eastern Time (utc_minus_05_00) and Intermediate experience level
checkpoints.push({
  passed: matchingWithPrefs.length > 0,
  weight: 0.50
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const quoteCarts = JSON.parse(localStorage.getItem('quote_carts') || '[]');
const quoteCartItems = JSON.parse(localStorage.getItem('quote_cart_items') || '[]');
const configs = JSON.parse(localStorage.getItem('server_configurations') || '[]');
const baseModels = JSON.parse(localStorage.getItem('server_base_models') || '[]');
const memOptions = JSON.parse(localStorage.getItem('server_memory_options') || '[]');
const storageOptions = JSON.parse(localStorage.getItem('server_storage_options') || '[]');
const maintenancePlans = JSON.parse(localStorage.getItem('maintenance_plans') || '[]');
const serverQuoteRequests = JSON.parse(localStorage.getItem('server_quote_requests') || '[]');

function isConfigQualifying(conf) {
  if (!conf) return false;
  const base = baseModels.find(b => b.id === conf.baseModelId);
  if (!base || base.formFactor !== 'rack') return false;

  const mem = memOptions.find(m => m.id === conf.memoryOptionId);
  if (!mem || typeof mem.sizeGB !== 'number' || mem.sizeGB < 32) return false;

  const storageIds = Array.isArray(conf.storageOptionIds) ? conf.storageOptionIds : [];
  const storageList = storageIds.map(id => storageOptions.find(s => s.id === id)).filter(Boolean);
  const totalTb = storageList.reduce((sum, s) => sum + (typeof s.capacityTB === 'number' ? s.capacityTB : 0), 0);
  if (totalTb < 2) return false;

  const plan = maintenancePlans.find(mp => mp.id === conf.maintenancePlanId);
  if (!plan || plan.durationYears !== 3) return false;

  const totalPrice = typeof conf.totalPrice === 'number' ? conf.totalPrice : 0;
  if (totalPrice < 3000 || totalPrice > 4000) return false;

  return true;
}

const qualifyingConfigs = configs.filter(isConfigQualifying);

let configInQuoteCart = null;
let configQuoteCartId = null;

for (const conf of qualifyingConfigs) {
  const item = quoteCartItems.find(qi => qi.serverConfigurationId === conf.id);
  if (item) {
    configInQuoteCart = conf;
    configQuoteCartId = item.quoteCartId;
    break;
  }
}

let hasQuoteRequest = false;
if (configQuoteCartId) {
  hasQuoteRequest = serverQuoteRequests.some(r => r.quoteCartId === configQuoteCartId && r.status === 'submitted');
}

// CP1 (0.40): A server configuration exists that meets rack form factor, >=32GB RAM, >=2TB storage, 3-year maintenance, and total price between $3,000 and $4,000
checkpoints.push({
  passed: qualifyingConfigs.length > 0,
  weight: 0.40
});

// CP2 (0.30): At least one such configuration has been added to a quote cart
checkpoints.push({
  passed: !!configInQuoteCart && !!configQuoteCartId,
  weight: 0.30
});

// CP3 (0.30): A server quote request has been submitted for the quote cart containing the qualifying configuration
checkpoints.push({
  passed: hasQuoteRequest,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
